#!/usr/bin/env python3
# plant — grow capabilities from a spec pasted in the browser (or piped in).
# argv[1] is the spec: a seed's events as JSONL (one {name,payload} per line),
# a JSON array, or a single JSON object. Each well-formed event is emitted as-is;
# the kernel's strange loop compiles any command.declared / projector.declared
# into real capabilities, and replays the rest. A seed.planted receipt summarizes
# the planting (so `self ls seeds` and the plant page show it). A bad spec comes
# back as a seed.planted with an error, so the page can show what went wrong.
import sys, json

spec = sys.argv[1] if len(sys.argv) > 1 else ""


def parse(text):
    text = text.strip()
    if not text:
        return []
    # Whole-blob JSON first: an array of events, or a single event object.
    try:
        v = json.loads(text)
        return v if isinstance(v, list) else [v]
    except json.JSONDecodeError:
        pass
    # Otherwise treat it as JSONL — one event per non-blank line (the seed format).
    out = []
    for ln in text.splitlines():
        ln = ln.strip()
        if ln:
            out.append(json.loads(ln))  # a bad line raises → caught by the caller
    return out


def receipt(ok, commands, projectors, replayed, error=""):
    payload = {"seed": "ui", "ok": ok, "commands": commands,
               "projectors": projectors, "events_replayed": replayed}
    if error:
        payload["error"] = error
    return json.dumps({"name": "seed.planted", "payload": payload})


try:
    events = parse(spec)
except Exception as e:
    print(receipt(False, [], [], 0, "parse error: %s" % e))
    sys.exit(0)

commands, projectors, replayed = [], [], 0
emitted = False
for ev in events:
    if not (isinstance(ev, dict) and ev.get("name") and ev.get("payload") is not None):
        continue
    name = ev["name"]
    print(json.dumps({"name": name, "payload": ev["payload"]}))
    emitted = True
    if name == "command.declared":
        commands.append(ev["payload"].get("name", "?"))
    elif name == "projector.declared":
        projectors.append(ev["payload"].get("name", "?"))
    else:
        replayed += 1

if not emitted:
    print(receipt(False, [], [], 0,
                  'no events found — paste one or more {"name":...,"payload":...} objects'))
else:
    print(receipt(True, commands, projectors, replayed))
